{{ config(materialized='table') }}\n\nSELECT\n    opp.opp_kennung AS \"Id\",\n    opp.titel AS \"Name\",\n    CASE\n        WHEN LOWER(TRIM(opp.vertriebsphase)) IN (\'prospecting\', \'prospect\', \'in kontakt\') THEN \'Prospecting\'\n        WHEN LOWER(TRIM(opp.vertriebsphase)) IN (\'qualification\', \'qualifikation\', \'quali\') THEN \'Qualification\'\n        WHEN LOWER(TRIM(opp.vertriebsphase)) IN (\'in prüfung\') THEN \'Negotiation/Review\' -- Best guess\n        WHEN LOWER(TRIM(opp.vertriebsphase)) IN (\'closed won\', \'won\', \'gewonnen\', \'abgeschlossen (gewonnen)\') THEN \'Closed Won\'\n        WHEN LOWER(TRIM(opp.vertriebsphase)) IN (\'closed lost\', \'lost\', \'verloren\', \'abgeschlossen (verloren)\') THEN \'Closed Lost\'\n        ELSE NULL\n    END AS \"StageName\",\n    CASE\n        WHEN opp.zieldatum ~ \'^\\d{4}-\\d{2}-\\d{2}$\' THEN TO_CHAR(TO_DATE(opp.zieldatum, \'YYYY-MM-DD\'), \'YYYY-MM-DD\')\n        WHEN opp.zieldatum ~ \'^\\d{8}$\' THEN TO_CHAR(TO_DATE(opp.zieldatum, \'YYYYMMDD\'), \'YYYY-MM-DD\')\n        WHEN opp.zieldatum ~ \'^\\d{2}\\.\\d{2}\\.\\d{4}$\' THEN TO_CHAR(TO_DATE(opp.zieldatum, \'DD.MM.YYYY\'), \'YYYY-MM-DD\')\n        WHEN opp.zieldatum ~ \'^\\d{1,2}/\\d{1,2}/\\d{4}$\' THEN TO_CHAR(TO_DATE(opp.zieldatum, \'MM/DD/YYYY\'), \'YYYY-MM-DD\')\n        ELSE NULL\n    END AS \"CloseDate\",\n    CASE\n        WHEN opp.auftragswert IS NULL OR TRIM(opp.auftragswert) = \'\' THEN NULL\n        ELSE\n            CASE\n                WHEN\n                    -- Check if it contains a comma (likely European format)\n                    TRIM(\n                        REPLACE(\n                            REPLACE(\n                                REPLACE(\n                                    REPLACE(\n                                        REPLACE(\n                                            REPLACE(\n                                                REPLACE(\n                                                    LOWER(opp.auftragswert),\n                                                \'€\', \'\'\n                                                ),\n                                            \'$\', \'\'\n                                            ),\n                                        \'usd\', \'\'\n                                        ),\n                                    \'eur\', \'\'\n                                    ),\n                                \'chf\', \'\'\n                                    ),\n                                \'euro\', \'\'\n                                    ),\n                        \' \', \'\'\n                        )\n                    ) ~ \'.*,.*\'\n                THEN\n                    CASE\n                        WHEN REPLACE(\n                                REPLACE(\n                                    TRIM(\n                                        REPLACE(\n                                            REPLACE(\n                                                REPLACE(\n                                                    REPLACE(\n                                                        REPLACE(\n                                                            REPLACE(\n                                                                REPLACE(\n                                                                    LOWER(opp.auftragswert),\n                                                                \'€\', \'\'\n                                                                ),\n                                                            \'$\', \'\'\n                                                            ),\n                                                        \'usd\', \'\'\n                                                        ),\n                                                    \'eur\', \'\'\n                                                    ),\n                                                \'chf\', \'\'\n                                                ),\n                                            \'euro\', \'\'\n                                            ),\n                                        \' \', \'\'\n                                        )\n                                    ),\n                                \'.\', \'\'\n                                ),\n                            \',\', \'.\'\n                        ) ~ \'^\-?\d+(\.\d+)?$\' THEN\n                            CAST(REPLACE(\n                                REPLACE(\n                                    TRIM(\n                                        REPLACE(\n                                            REPLACE(\n                                                REPLACE(\n                                                    REPLACE(\n                                                        REPLACE(\n                                                            REPLACE(\n                                                                REPLACE(\n                                                                    LOWER(opp.auftragswert),\n                                                                \'€\', \'\'\n                                                                ),\n                                                            \'$\', \'\'\n                                                            ),\n                                                        \'usd\', \'\'\n                                                        ),\n                                                    \'eur\', \'\'\n                                                    ),\n                                                \'chf\', \'\'\n                                                ),\n                                            \'euro\', \'\'\n                                            ),\n                                        \' \', \'\'\n                                        )\n                                    ),\n                                \'.\', \'\'\n                                ),\n                            \',\', \'.\'\n                            ) AS DOUBLE PRECISION)\n                        ELSE NULL\n                    END\n                ELSE\n                    CASE\n                        WHEN TRIM(\n                                REPLACE(\n                                    REPLACE(\n                                        REPLACE(\n                                            REPLACE(\n                                                REPLACE(\n                                                    REPLACE(\n                                                        REPLACE(\n                                                            LOWER(opp.auftragswert),\n                                                        \'€\', \'\'\n                                                        ),\n                                                    \'$\', \'\'\n                                                    ),\n                                                \'usd\', \'\'\n                                                ),\n                                            \'eur\', \'\'\n                                            ),\n                                        \'chf\', \'\'\n                                            ),\n                                        \'euro\', \'\'\n                                            ),\n                                    \' \', \'\'\n                                    )\n                                ) ~ \'^\-?\d+(\.\d+)?$\' THEN\n                            CAST(TRIM(\n                                REPLACE(\n                                    REPLACE(\n                                        REPLACE(\n                                            REPLACE(\n                                                REPLACE(\n                                                    REPLACE(\n                                                        REPLACE(\n                                                            LOWER(opp.auftragswert),\n                                                        \'€\', \'\'\n                                                        ),\n                                                    \'$\', \'\'\n                                                    ),\n                                                \'usd\', \'\'\n                                                ),\n                                            \'eur\', \'\'\n                                            ),\n                                        \'chf\', \'\'\n                                            ),\n                                        \'euro\', \'\'\n                                            ),\n                                    \' \', \'\'\n                                    )\n                                ) AS DOUBLE PRECISION)\n                        ELSE NULL\n                    END\n            END\n    END AS \"Amount\",\n    CASE\n        WHEN LOWER(TRIM(opp.waehrungscode)) IN (\'eur\', \'€\', \'euro\') THEN \'EUR\'\n        WHEN LOWER(TRIM(opp.waehrungscode)) IN (\'usd\', \'$\') THEN \'USD\'\n        WHEN LOWER(TRIM(opp.waehrungscode)) IN (\'chf\') THEN \'CHF\'\n        ELSE NULL\n    END AS \"CurrencyIsoCode\",\n    REPLACE(opp.kunden_ref, \'KD-\', \'CUST-\') AS \"AccountId\",\n    opp.opp_kennung AS \"Legacy_Opportunity_ID__c\",\n    NULL AS \"CreatedDate\",\n    NULL AS \"LastModifiedDate\",\n    0 AS \"IsDeleted\"\nFROM\n    {{ source(\'fixture_master_v2_src\', \'master_opportunities\') }} AS opp\n